arguments.argument:
if bSizeUp=false
{
  sizeMod-=0.002
  if sizeMod<=0 {bSizeUp=true}
}
else
{
  sizeMod+=0.002
  if sizeMod>=0.07 {bSizeUp=false}
}

if surface_exists(surf)
{
  surface_set_target(surf)
  draw_clear_alpha(c_black,1)
  draw_set_blend_mode(bm_subtract)
  draw_sprite_ext(sSurfOmniLightA,0,oPlayer1.x,oPlayer1.y-26,2+sizeMod,2+sizeMod,0,c_white,1)
  if oIdentifier.bChaoActive=1 {draw_sprite_ext(sSurfOmniLightA,0,oIdentifier.x,oIdentifier.y,1.75+sizeMod,1.75+sizeMod,0,c_white,1)}
  with oEnemyBase
  {
    draw_sprite_ext(sSurfOmniLightA,0,x+8,y+8,1+oSurfLightF.sizeMod,1+oSurfLightF.sizeMod,0,c_white,0.65)
  }
  with oCaveTorch
  {
    draw_sprite_ext(sSurfOmniLightA,0,x,y-8,1.1+oSurfLightF.sizeMod,1.1.25+oSurfLightF.sizeMod,0,c_white,0.75)
  }
  if instance_exists(oWepEf_Light)
  {
    with oWepEf_Light
    {
      draw_sprite_ext(sSurfOmniLightA,0,x,y,image_xscale,image_yscale,image_angle,c_white,image_alpha)
    }
  }
  surface_reset_target()
  draw_set_blend_mode(bm_normal)
}
